export const getProductBySlug = (slug: string) => products.find(p => p.slug === slug);
export const getProductsByCategory = (cat: string) => cat === 'All' ? products : products.filter(p => p.category === cat);
export const getRelatedProducts = (product: Product, limit = 4) => products.filter(p => p.category === product.category && p.id !== product.id).slice(0, limit);
